incorrect:
// INCORRECT: Browser code mixes Next.js BFF and direct NestJS origins.
export async function saveUser(user: UserInput) {
  await fetch("/api/users", { method: "POST", body: JSON.stringify(user) });
  await fetch("https://api.example.com/audit", { method: "POST" });
}

correct:
// CORRECT: Browser code talks to one public boundary.
export async function saveUser(user: UserInput) {
  await fetch("/api/users", {
    method: "POST",
    body: JSON.stringify(user),
  });
}

incorrect:
// INCORRECT: The frontend deploy does not verify backend health or client drift.
export async function release() {
  await deployWeb();
}

correct:
// CORRECT: Release checks verify backend and generated client compatibility.
export async function release() {
  await verifyApiHealth();
  await verifyOpenApiClientIsCurrent();
  await deployWeb();
}

incorrect:
// INCORRECT: Next.js duplicates a backend DTO by hand.
export async function createUser(name: string) {
  return fetch(`${process.env.NEXT_SERVER_API_ORIGIN}/users`, {
    method: "POST",
    body: JSON.stringify({ fullName: name }),
  });
}

correct:
// CORRECT: Next.js uses a generated client from the NestJS OpenAPI contract.
import { api } from "@/generated/api-client";

export async function createUser(name: string) {
  return api.users.createUser({
    body: { name },
  });
}

incorrect:
// INCORRECT: Server Component self-fetches the same Next.js app.
export default async function ProductsPage() {
  const res = await fetch(`${process.env.NEXT_PUBLIC_APP_URL}/api/products`);
  const products = await res.json();
  return <Products products={products} />;
}

correct:
// CORRECT: Server Component calls the backend client directly.
import { api } from "@/generated/api-client";

export default async function ProductsPage() {
  const products = await api.products.list();
  return <Products products={products} />;
}

incorrect:
// INCORRECT: Forwards all browser headers to the backend.
import { headers } from "next/headers";

export async function getMe() {
  return fetch(`${process.env.NEXT_SERVER_API_ORIGIN}/me`, {
    headers: await headers(),
  });
}

correct:
// CORRECT: Derive a trusted session and send only the backend credential.
import { auth } from "@/lib/auth";
import { api } from "@/generated/api-client";

export async function getMe() {
  const session = await auth();
  return api.withToken(session.backendAccessToken).users.me();
}

incorrect:
// INCORRECT: A backend secret is exposed to the browser.
export const env = {
  apiSecret: process.env.NEXT_PUBLIC_API_SECRET!,
};

correct:
// CORRECT: Public, Next.js server-only, and NestJS backend env are separate.
export const webPublicEnv = {
  appUrl: process.env.NEXT_PUBLIC_APP_URL!,
};

export const webServerEnv = {
  apiOrigin: process.env.NEXT_SERVER_API_ORIGIN!,
};
